90:     CurrencyAmount counter = product.getUnderlying().getCounterCurrencyAmount();
91:     buf.append(product.getLongShort());
92:     buf.append(' ');
93:     buf.append(SummarizerUtils.fx(base, counter));
94:     buf.append(" Premium ");
