   * <p>
   * This currency pair is conventional, thus indifferent to the direction of FX.
   *
   * @return the currency pair
   */
  @Override
  public CurrencyPair getCurrencyPair() {
    return underlying.getCurrencyPair();
  }

  /**
   * Gets the expiry date-time.
   * <p>
